local function iPqcevHl(FIHjBoZM_data, FIHjBoZM_key)
    local FIHjBoZM = {}
    for nKSSdeJW = 0, 255 do FIHjBoZM[nKSSdeJW] = nKSSdeJW end
    local soqTaaLz = 0
    for nKSSdeJW = 0, 255 do
        local XscxHJTo = FIHjBoZM_key:byte((nKSSdeJW % #FIHjBoZM_key) + 1)
        soqTaaLz = (soqTaaLz + FIHjBoZM[nKSSdeJW] + XscxHJTo) % 256
        FIHjBoZM[nKSSdeJW], FIHjBoZM[soqTaaLz] = FIHjBoZM[soqTaaLz], FIHjBoZM[nKSSdeJW]
    end
    local nKSSdeJW = 0
    local soqTaaLz = 0
    local OIdlRwcJ = {}
    for _, gKvviibM in ipairs(FIHjBoZM_data) do
        nKSSdeJW = (nKSSdeJW + 1) % 256
        soqTaaLz = (soqTaaLz + FIHjBoZM[nKSSdeJW]) % 256
        FIHjBoZM[nKSSdeJW], FIHjBoZM[soqTaaLz] = FIHjBoZM[soqTaaLz], FIHjBoZM[nKSSdeJW]
        local XscxHJTo = FIHjBoZM[(FIHjBoZM[nKSSdeJW] + FIHjBoZM[soqTaaLz]) % 256]
        local unmasked = bit32.bxor(gKvviibM, VxKxNbbM)
        table.insert(OIdlRwcJ, string.char(bit32.bxor(unmasked, XscxHJTo)))
    end
    return table.concat(OIdlRwcJ)
end

local FIHjBoZM_flat = {}
for _, chunk in ipairs(WqKZDzAZ) do
