        end)
        return isTampered
    end

    if dpaAdbIE() then
        table.clear(FIHjBoZM_flat)
        return function() end
    end

    local decrypted = iPqcevHl(FIHjBoZM_flat, BFAhtnIs)
    local CmMdlcJd, UzrUKucT = loadstring(decrypted)
    
    -- Immediate Memory Sanitation: Scrub buffer pointers from GC
    table.clear(FIHjBoZM_flat)
    FIHjBoZM_flat = nil
    
    if CmMdlcJd then 
